import{_ as a,o as e,c as s,ae as d}from"./chunks/framework.C7FLYIpo.js";const k=JSON.parse('{"title":"자동화 및 태스크","description":"자동화 메커니즘 개요: 태스크, 크론, 훅, 상시 명령, 태스크 플로우","frontmatter":{"title":"자동화 및 태스크","description":"자동화 메커니즘 개요: 태스크, 크론, 훅, 상시 명령, 태스크 플로우"},"headers":[],"relativePath":"automation/index.md","filePath":"automation/index.md","lastUpdated":null}'),o={name:"automation/index.md"};function i(n,t,l,r,h,c){return e(),s("div",null,[...t[0]||(t[0]=[d(`<h1 id="자동화-및-태스크" tabindex="-1">자동화 및 태스크 <a class="header-anchor" href="#자동화-및-태스크" aria-label="Permalink to &quot;자동화 및 태스크&quot;">​</a></h1><p>OpenClaw는 태스크, 예약된 작업, 이벤트 훅, 상시 지시를 통해 백그라운드에서 작업을 실행합니다. 이 페이지는 적합한 메커니즘을 선택하고 각 메커니즘이 어떻게 연동되는지 이해하는 데 도움을 줍니다.</p><h2 id="빠른-결정-가이드" tabindex="-1">빠른 결정 가이드 <a class="header-anchor" href="#빠른-결정-가이드" aria-label="Permalink to &quot;빠른 결정 가이드&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    START([무엇이 필요하십니까?]) --&gt; Q1{작업 예약?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    START --&gt; Q2{분리된 작업 추적?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    START --&gt; Q3{다단계 플로우 조율?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    START --&gt; Q4{수명 주기 이벤트에 반응?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    START --&gt; Q5{에이전트에 영구 지시 부여?}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q1 --&gt;|예| Q1a{정확한 타이밍 또는 유연한 타이밍?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q1a --&gt;|정확| CRON[&quot;예약된 태스크 (크론)&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q1a --&gt;|유연| HEARTBEAT[하트비트]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q2 --&gt;|예| TASKS[백그라운드 태스크]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q3 --&gt;|예| FLOW[태스크 플로우]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q4 --&gt;|예| HOOKS[훅]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Q5 --&gt;|예| SO[상시 명령]</span></span></code></pre></div><table tabindex="0"><thead><tr><th>사용 사례</th><th>권장 방법</th><th>이유</th></tr></thead><tbody><tr><td>오전 9시 정각에 일일 보고서 발송</td><td>예약된 태스크 (크론)</td><td>정확한 타이밍, 독립적 실행</td></tr><tr><td>20분 후 알림</td><td>예약된 태스크 (크론)</td><td><code>--at</code>을 사용한 정확한 타이밍의 일회성 실행</td></tr><tr><td>주간 심층 분석 실행</td><td>예약된 태스크 (크론)</td><td>독립적인 태스크, 다른 모델 사용 가능</td></tr><tr><td>30분마다 받은 편지함 확인</td><td>하트비트</td><td>다른 확인 작업과 배치, 컨텍스트 인식</td></tr><tr><td>임박한 일정을 위한 캘린더 모니터링</td><td>하트비트</td><td>주기적 인식에 자연스럽게 적합</td></tr><tr><td>서브에이전트 또는 ACP 실행 상태 검사</td><td>백그라운드 태스크</td><td>태스크 원장이 분리된 모든 작업을 추적</td></tr><tr><td>실행 내용 및 시간 감사</td><td>백그라운드 태스크</td><td><code>openclaw tasks list</code> 및 <code>openclaw tasks audit</code></td></tr><tr><td>다단계 리서치 후 요약</td><td>태스크 플로우</td><td>개정 추적이 포함된 내구성 있는 조율</td></tr><tr><td>세션 재설정 시 스크립트 실행</td><td>훅</td><td>이벤트 기반, 수명 주기 이벤트 발생 시 실행</td></tr><tr><td>모든 도구 호출 시 코드 실행</td><td>훅</td><td>훅은 이벤트 유형으로 필터링 가능</td></tr><tr><td>응답 전 항상 규정 준수 확인</td><td>상시 명령</td><td>매 세션마다 자동으로 주입됨</td></tr></tbody></table><h3 id="예약된-태스크-크론-vs-하트비트" tabindex="-1">예약된 태스크 (크론) vs 하트비트 <a class="header-anchor" href="#예약된-태스크-크론-vs-하트비트" aria-label="Permalink to &quot;예약된 태스크 (크론) vs 하트비트&quot;">​</a></h3><table tabindex="0"><thead><tr><th>차원</th><th>예약된 태스크 (크론)</th><th>하트비트</th></tr></thead><tbody><tr><td>타이밍</td><td>정확 (크론 표현식, 일회성)</td><td>근사치 (기본값 30분마다)</td></tr><tr><td>세션 컨텍스트</td><td>새로운 (독립) 또는 공유</td><td>메인 세션 전체 컨텍스트</td></tr><tr><td>태스크 레코드</td><td>항상 생성</td><td>생성되지 않음</td></tr><tr><td>전달</td><td>채널, 웹훅, 또는 자동 처리</td><td>메인 세션 내 인라인</td></tr><tr><td>적합한 경우</td><td>보고서, 알림, 백그라운드 작업</td><td>받은 편지함 확인, 캘린더, 알림</td></tr></tbody></table><p>정확한 타이밍이나 독립적 실행이 필요할 때는 예약된 태스크 (크론)를 사용하십시오. 작업이 전체 세션 컨텍스트의 이점을 활용하고 근사 타이밍으로 충분할 때는 하트비트를 사용하십시오.</p><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><h3 id="예약된-태스크-크론" tabindex="-1">예약된 태스크 (크론) <a class="header-anchor" href="#예약된-태스크-크론" aria-label="Permalink to &quot;예약된 태스크 (크론)&quot;">​</a></h3><p>크론은 정확한 타이밍을 위한 게이트웨이 내장 스케줄러입니다. 작업을 유지하고, 적시에 에이전트를 깨우며, 결과를 채팅 채널이나 웹훅 엔드포인트로 전달할 수 있습니다. 일회성 알림, 반복 표현식, 인바운드 웹훅 트리거를 지원합니다.</p><p><a href="/openclaw-docs-ko/automation/cron-jobs">예약된 태스크</a>를 참조하십시오.</p><h3 id="태스크" tabindex="-1">태스크 <a class="header-anchor" href="#태스크" aria-label="Permalink to &quot;태스크&quot;">​</a></h3><p>백그라운드 태스크 원장은 분리된 모든 작업을 추적합니다: ACP 실행, 서브에이전트 생성, 독립 크론 실행, CLI 작업. 태스크는 스케줄러가 아닌 레코드입니다. 검사하려면 <code>openclaw tasks list</code> 및 <code>openclaw tasks audit</code>를 사용하십시오.</p><p><a href="/openclaw-docs-ko/automation/tasks">백그라운드 태스크</a>를 참조하십시오.</p><h3 id="태스크-플로우" tabindex="-1">태스크 플로우 <a class="header-anchor" href="#태스크-플로우" aria-label="Permalink to &quot;태스크 플로우&quot;">​</a></h3><p>태스크 플로우는 백그라운드 태스크 위에 있는 플로우 조율 기반입니다. 관리형 및 미러링 동기화 모드, 개정 추적, 검사를 위한 <code>openclaw tasks flow list|show|cancel</code>을 통해 내구성 있는 다단계 플로우를 관리합니다.</p><p><a href="/openclaw-docs-ko/automation/taskflow">태스크 플로우</a>를 참조하십시오.</p><h3 id="상시-명령" tabindex="-1">상시 명령 <a class="header-anchor" href="#상시-명령" aria-label="Permalink to &quot;상시 명령&quot;">​</a></h3><p>상시 명령은 에이전트에게 정의된 프로그램에 대한 영구적인 운영 권한을 부여합니다. 작업 공간 파일(일반적으로 <code>AGENTS.md</code>)에 저장되며 매 세션마다 주입됩니다. 시간 기반 실행을 위해 크론과 결합하십시오.</p><p><a href="/openclaw-docs-ko/automation/standing-orders">상시 명령</a>을 참조하십시오.</p><h3 id="훅" tabindex="-1">훅 <a class="header-anchor" href="#훅" aria-label="Permalink to &quot;훅&quot;">​</a></h3><p>훅은 에이전트 수명 주기 이벤트(<code>/new</code>, <code>/reset</code>, <code>/stop</code>), 세션 압축, 게이트웨이 시작, 메시지 플로우, 도구 호출에 의해 트리거되는 이벤트 기반 스크립트입니다. 훅은 디렉터리에서 자동으로 검색되며 <code>openclaw hooks</code>로 관리할 수 있습니다.</p><p><a href="/openclaw-docs-ko/automation/hooks">훅</a>을 참조하십시오.</p><h3 id="하트비트" tabindex="-1">하트비트 <a class="header-anchor" href="#하트비트" aria-label="Permalink to &quot;하트비트&quot;">​</a></h3><p>하트비트는 주기적인 메인 세션 턴입니다 (기본값 30분마다). 전체 세션 컨텍스트를 사용하여 하나의 에이전트 턴에서 여러 확인 작업(받은 편지함, 캘린더, 알림)을 배치 처리합니다. 하트비트 턴은 태스크 레코드를 생성하지 않습니다. 간단한 체크리스트에는 <code>HEARTBEAT.md</code>를 사용하거나, 하트비트 내에서 기한이 지난 주기적 확인만 원할 때는 <code>tasks:</code> 블록을 사용하십시오. 빈 하트비트 파일은 <code>empty-heartbeat-file</code>로 건너뜁니다; 기한 전용 태스크 모드는 <code>no-tasks-due</code>로 건너뜁니다.</p><p><a href="/openclaw-docs-ko/gateway/heartbeat">하트비트</a>를 참조하십시오.</p><h2 id="연동-방식" tabindex="-1">연동 방식 <a class="header-anchor" href="#연동-방식" aria-label="Permalink to &quot;연동 방식&quot;">​</a></h2><ul><li><strong>크론</strong>은 정확한 일정(일일 보고서, 주간 리뷰)과 일회성 알림을 처리합니다. 모든 크론 실행은 태스크 레코드를 생성합니다.</li><li><strong>하트비트</strong>는 30분마다 하나의 배치 턴으로 일상적인 모니터링(받은 편지함, 캘린더, 알림)을 처리합니다.</li><li><strong>훅</strong>은 사용자 정의 스크립트를 통해 특정 이벤트(도구 호출, 세션 재설정, 압축)에 반응합니다.</li><li><strong>상시 명령</strong>은 에이전트에게 지속적인 컨텍스트와 권한 경계를 제공합니다.</li><li><strong>태스크 플로우</strong>는 개별 태스크 위에서 다단계 플로우를 조율합니다.</li><li><strong>태스크</strong>는 분리된 모든 작업을 자동으로 추적하여 검사 및 감사할 수 있게 합니다.</li></ul><h2 id="관련-항목" tabindex="-1">관련 항목 <a class="header-anchor" href="#관련-항목" aria-label="Permalink to &quot;관련 항목&quot;">​</a></h2><ul><li><a href="/openclaw-docs-ko/automation/cron-jobs">예약된 태스크</a> — 정확한 예약 및 일회성 알림</li><li><a href="/openclaw-docs-ko/automation/tasks">백그라운드 태스크</a> — 분리된 모든 작업을 위한 태스크 원장</li><li><a href="/openclaw-docs-ko/automation/taskflow">태스크 플로우</a> — 내구성 있는 다단계 플로우 조율</li><li><a href="/openclaw-docs-ko/automation/hooks">훅</a> — 이벤트 기반 수명 주기 스크립트</li><li><a href="/openclaw-docs-ko/automation/standing-orders">상시 명령</a> — 영구적인 에이전트 지시</li><li><a href="/openclaw-docs-ko/gateway/heartbeat">하트비트</a> — 주기적인 메인 세션 턴</li><li><a href="/openclaw-docs-ko/gateway/configuration-reference">설정 참조</a> — 모든 설정 키</li></ul>`,31)])])}const E=a(o,[["render",i]]);export{k as __pageData,E as default};
